public class FileTransferService extends FileTransferGrpc.FileTransferImplBase {
    private static final Logger logger = Logger.getLogger(FileTransferService.class.getName());
    private static final int CHUNK_SIZE = 1024 * 1024; // 1MB chunks

    @Override
    public StreamObserver<UploadRequest> uploadFile(StreamObserver<UploadResponse> responseObserver) {
        return new StreamObserver<UploadRequest>() {
            private FileOutputStream fileOutputStream;
            private String fileName;
            private long totalBytes = 0;

            @Override
            public void onNext(UploadRequest request) {
                try {
                    if (fileName == null) {
                        fileName = request.getFileName();
                        fileOutputStream = new FileOutputStream(fileName);
                    }
                    
                    if (request.hasData()) {
                        fileOutputStream.write(request.getData().toByteArray());
                        totalBytes += request.getData().size();
                    }
                    
                    if (request.getIsLast()) {
                        fileOutputStream.close();
                        responseObserver.onNext(UploadResponse.newBuilder()
                                .setFileName(fileName)
                                .setTotalBytes(totalBytes)
                                .setSuccess(true)
                                .build());
                        responseObserver.onCompleted();
                    }
                } catch (IOException e) {
                    logger.log(Level.SEVERE, "Error during file upload", e);
                    responseObserver.onError(Status.INTERNAL.withDescription("Upload failed").withCause(e).asException());
                }
            }

            @Override
            public void onError(Throwable t) {
                logger.log(Level.SEVERE, "Upload error", t);
                try {
                    if (fileOutputStream != null) {
                        fileOutputStream.close();
                    }
                } catch (IOException e) {
                    logger.log(Level.SEVERE, "Error closing file", e);
                }
                responseObserver.onError(t);
            }

            @Override
            public void onCompleted() {
                logger.info("Upload completed for file: " + fileName);
            }
        };
    }

    @Override
    public void downloadFile(DownloadRequest request, StreamObserver<DownloadResponse> responseObserver) {
        try {
            String fileName = request.getFileName();
            File file = new File(fileName);
            
            if (!file.exists()) {
                responseObserver.onError(Status.NOT_FOUND.withDescription("File not found").asException());
                return;
            }

            FileInputStream fileInputStream = new FileInputStream(file);
            byte[] buffer = new byte[CHUNK_SIZE];
            long totalBytes = file.length();
            long bytesSent = 0;

            while (bytesSent < totalBytes) {
                int bytesRead = fileInputStream.read(buffer);
                if (bytesRead == -1) break;

                DownloadResponse response = DownloadResponse.newBuilder()
                        .setData(ByteString.copyFrom(buffer, 0, bytesRead))
                        .setProgress((double) bytesSent / totalBytes * 100)
                        .build();
                
                responseObserver.onNext(response);
                bytesSent += bytesRead;
            }

            fileInputStream.close();
            responseObserver.onCompleted();
        } catch (IOException e) {
            logger.log(Level.SEVERE, "Error during file download", e);
            responseObserver.onError(Status.INTERNAL.withDescription("Download failed").withCause(e).asException());
        }
    }

    @Override
    public StreamObserver<TransferRequest> transferData(StreamObserver<TransferResponse> responseObserver) {
        return new StreamObserver<TransferRequest>() {
            private final ExecutorService executor = Executors.newCachedThreadPool();
            private final BlockingQueue<TransferRequest> requestQueue = new LinkedBlockingQueue<>();
            private final BlockingQueue<TransferResponse> responseQueue = new LinkedBlockingQueue<>();
            private volatile boolean isProcessing = false;

            @Override
            public void onNext(TransferRequest request) {
                try {
                    requestQueue.offer(request);
                    if (!isProcessing) {
                        isProcessing = true;
                        executor.submit(this::processRequests);
                    }
                } catch (Exception e) {
                    logger.log(Level.SEVERE, "Error in transferData", e);
                    responseObserver.onError(e);
                }
            }

            private void processRequests() {
                try {
                    while (!requestQueue.isEmpty() || isProcessing) {
                        TransferRequest request = requestQueue.poll(1, TimeUnit.SECONDS);
                        if (request != null) {
                            TransferResponse response = processRequest(request);
                            responseObserver.onNext(response);
                        }
                    }
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                } catch (Exception e) {
                    logger.log(Level.SEVERE, "Error processing requests", e);
                    responseObserver.onError(e);
                }
            }

            private TransferResponse processRequest(TransferRequest request) {
                return TransferResponse.newBuilder()
                        .setProcessedData(request.getData())
                        .setTimestamp(System.currentTimeMillis())
                        .build();
            }

            @Override
            public void onError(Throwable t) {
                logger.log(Level.SEVERE, "Transfer error", t);
                responseObserver.onError(t);
                executor.shutdown();
            }

            @Override
            public void onCompleted() {
                logger.info("Transfer completed");
                responseObserver.onCompleted();
                executor.shutdown();
            }
        };
    }
}

